-- Textarea: multi-line text input
Section.AddTextarea = function(self, opts)
    assert(type(opts) == "table", "AddTextarea: opts must be a table")
    local flag = self:_registerFlag(opts.ID, opts.Default or "")

    local card, stroke = self:_makeCard()
    card.Size = UDim2.new(1, 0, 0, 96)

    local col = Instance.new("UIListLayout")
    col.FillDirection = Enum.FillDirection.Vertical
    col.Padding       = UDim.new(0, 5)
    col.Parent        = card

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size                   = UDim2.new(1, 0, 0, 13)
    title.Text                   = opts.Title or ""
    title.Font                   = Layout.FONT_TITLE
    title.TextSize               = Layout.TITLE_SIZE
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = card

    -- Textarea wrapper
    local wrap = Instance.new("Frame")
    wrap.BackgroundColor3 = Theme:BG(1)
    wrap.BorderSizePixel  = 0
    wrap.Size             = UDim2.new(1, 0, 0, 70)
    wrap.ClipsDescendants = true
    wrap.Parent           = card

    local wrapCorner = Instance.new("UICorner")
    wrapCorner.CornerRadius = UDim.new(0, 6)
    wrapCorner.Parent       = wrap

    local wrapStroke = Instance.new("UIStroke")
    wrapStroke.Color     = Theme:Border(1)
    wrapStroke.Thickness = 1
    wrapStroke.Parent    = wrap

    local pad = Instance.new("UIPadding")
    pad.PaddingLeft   = UDim.new(0, 9)
    pad.PaddingRight  = UDim.new(0, 9)
    pad.PaddingTop    = UDim.new(0, 7)
    pad.PaddingBottom = UDim.new(0, 7)
    pad.Parent        = wrap

    local box = Instance.new("TextBox")
    box.BackgroundTransparency = 1
    box.BorderSizePixel        = 0
    box.Size                   = UDim2.new(1, 0, 1, 0)
    box.Text                   = opts.Default or ""
    box.PlaceholderText        = opts.Placeholder or ""
    box.PlaceholderColor3      = Theme:Text(4)
    box.Font                   = Enum.Font.Gotham
    box.TextSize               = Layout.VALUE_SIZE
    box.TextColor3             = Theme:Text(0)
    box.TextXAlignment         = Enum.TextXAlignment.Left
    box.TextYAlignment         = Enum.TextYAlignment.Top
    box.MultiLine              = true
    box.ClearTextOnFocus       = false
    box.TextWrapped            = true
    box.Parent                 = wrap

    box.Focused:Connect(function()
        Tween.fast(wrapStroke, { Color = Theme:Accent() })
    end)

    box.FocusLost:Connect(function()
        Tween.fast(wrapStroke, { Color = Theme:Border(1) })
        if flag then flag:_fire(box.Text) end
        if opts.Callback then pcall(opts.Callback, box.Text) end
    end)

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    if flag then
        flag:OnChanged(function(v)
            box.Text = tostring(v)
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/input/Dropdown.lua ──────────────────────────
-- Dropdown: single select dengan optional search untuk large list
Section.AddDropdown = function(self, opts)
    assert(type(opts) == "table", "AddDropdown: opts must be a table")
    local items      = opts.Options or opts.Items or {}
    local default    = opts.Default  or (items[1] or "")
    local searchable = opts.Searchable or (#items > 10)
    local flag       = self:_registerFlag(opts.ID, default)

    local card, stroke = self:_makeCard()
    card.ClipsDescendants = false
    card.Size             = UDim2.new(1, 0, 0, 60)

    for _, c in ipairs(card:GetChildren()) do
        if c:IsA("UIPadding") then c:Destroy() end
    end

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size                   = UDim2.new(1, -24, 0, 14)
    title.Position               = UDim2.new(0, 12, 0, 10)
    title.Text                   = opts.Title or ""
    title.Font                   = Layout.FONT_TITLE
    title.TextSize               = Layout.TITLE_SIZE
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = card

    -- Trigger button
    local trigger = Instance.new("TextButton")
    trigger.BackgroundColor3 = Theme:BG(1)
    trigger.BorderSizePixel  = 0
    trigger.Size             = UDim2.new(1, -24, 0, 28)
    trigger.Position         = UDim2.new(0, 12, 0, 28)
    trigger.Text             = ""
    trigger.AutoButtonColor  = false
    trigger.Parent           = card

    local trigCorner = Instance.new("UICorner")
    trigCorner.CornerRadius = UDim.new(0, 6)
    trigCorner.Parent       = trigger

    local trigStroke = Instance.new("UIStroke")
    trigStroke.Color     = Theme:Border(1)
    trigStroke.Thickness = 1
    trigStroke.Parent    = trigger

    local trigPad = Instance.new("UIPadding")
    trigPad.PaddingLeft  = UDim.new(0, 9)
    trigPad.PaddingRight = UDim.new(0, 9)
    trigPad.Parent       = trigger

    local valLbl = Instance.new("TextLabel")
    valLbl.BackgroundTransparency = 1
    valLbl.Size                   = UDim2.new(1, -16, 1, 0)
    valLbl.Text                   = default
    valLbl.Font                   = Layout.FONT_BODY
    valLbl.TextSize               = Layout.VALUE_SIZE
    valLbl.TextColor3             = Theme:Text(2)
    valLbl.TextXAlignment         = Enum.TextXAlignment.Left
    valLbl.Parent                 = trigger

    local arrow = Instance.new("TextLabel")
    arrow.BackgroundTransparency = 1
    arrow.Size                   = UDim2.fromOffset(12, 28)
    arrow.Position               = UDim2.new(1, -12, 0, 0)
    arrow.Text                   = "▾"
    arrow.Font                   = Enum.Font.Gotham
    arrow.TextSize               = 12
    arrow.TextColor3             = Theme:Text(3)
    arrow.Parent                 = trigger

    -- Helper: traverse up to find ScreenGui
    local function getScreenGui(inst)
        local p = inst
        while p do
            if p:IsA("ScreenGui") then return p end
            p = p.Parent
        end
        return nil
    end

    -- Invisible blocker — covers entire screen, ZIndex di bawah menu
    local blocker = Instance.new("TextButton")
    blocker.BackgroundTransparency = 1
    blocker.BorderSizePixel        = 0
    blocker.Size                   = UDim2.new(1, 0, 1, 0)
    blocker.Position               = UDim2.new(0, 0, 0, 0)
    blocker.Text                   = ""
    blocker.AutoButtonColor        = false
    blocker.ZIndex = 3
    blocker.Visible                = false
    blocker.Parent                 = card

    -- Connect sekali saja
    blocker.MouseButton1Click:Connect(function() _close() end)

    -- Menu: di-parent ke ScreenGui saat open agar tidak ter-clip ScrollingFrame
    local menu = Instance.new("Frame")
    menu.BackgroundColor3 = Theme:BG(3)
    menu.BorderSizePixel  = 0
    menu.Size             = UDim2.fromOffset(200, 0)
    menu.Position         = UDim2.fromOffset(0, 0)
    menu.Visible          = false
    menu.ZIndex = 3
    menu.ClipsDescendants = false
    menu.Parent           = card

    local menuCorner = Instance.new("UICorner")
    menuCorner.CornerRadius = UDim.new(0, 7)
    menuCorner.Parent       = menu

    local menuStroke = Instance.new("UIStroke")
    menuStroke.Color     = Theme:Border(2)
    menuStroke.Thickness = 1
    menuStroke.Parent    = menu

    -- Search bar (only if searchable)
    local searchBox = nil
    if searchable then
        local searchWrap = Instance.new("Frame")
        searchWrap.BackgroundTransparency = 1
        searchWrap.Size                   = UDim2.new(1, 0, 0, 32)
        searchWrap.ZIndex = 3
        searchWrap.Parent                 = menu

        local sPad = Instance.new("UIPadding")
        sPad.PaddingLeft   = UDim.new(0, 7)
        sPad.PaddingRight  = UDim.new(0, 7)
        sPad.PaddingTop    = UDim.new(0, 5)
        sPad.PaddingBottom = UDim.new(0, 5)
        sPad.Parent        = searchWrap

        local sBox = Instance.new("TextBox")
        sBox.BackgroundColor3  = Theme:BG(1)
        sBox.BorderSizePixel   = 0
        sBox.Size              = UDim2.new(1, 0, 1, 0)
        sBox.PlaceholderText   = "Search..."
        sBox.PlaceholderColor3 = Theme:Text(4)
        sBox.Text              = ""
        sBox.Font              = Enum.Font.Gotham
        sBox.TextSize          = 11
        sBox.TextColor3        = Theme:Text(0)
        sBox.ClearTextOnFocus  = false
        sBox.ZIndex = 3
        sBox.Parent            = searchWrap

        local sCorner = Instance.new("UICorner")
        sCorner.CornerRadius = UDim.new(0, 5)
        sCorner.Parent       = sBox

        local sPad2 = Instance.new("UIPadding")
        sPad2.PaddingLeft  = UDim.new(0, 7)
        sPad2.PaddingRight = UDim.new(0, 7)
        sPad2.Parent       = sBox

        local divLine = Instance.new("Frame")
        divLine.BackgroundColor3 = Theme:Border(0)
        divLine.BorderSizePixel  = 0
        divLine.Size             = UDim2.new(1, 0, 0, 1)
        divLine.Position         = UDim2.new(0, 0, 1, 0)
        divLine.Parent           = searchWrap

        searchBox = sBox
    end

    -- Scrollable list
    local list = Instance.new("ScrollingFrame")
    list.BackgroundTransparency  = 1
    list.BorderSizePixel         = 0
    list.Size                    = UDim2.new(1, 0, 1, searchable and -33 or 0)
    list.Position                = UDim2.new(0, 0, 0, searchable and 33 or 0)
    list.CanvasSize              = UDim2.new(0, 0, 0, 0)
    list.AutomaticCanvasSize     = Enum.AutomaticSize.Y
    list.ScrollBarThickness      = 2
    list.ScrollBarImageColor3    = Theme:BG(4)
    list.ZIndex = 3
    list.Parent                  = menu

    local listLayout = Instance.new("UIListLayout")
    listLayout.FillDirection = Enum.FillDirection.Vertical
    listLayout.SortOrder     = Enum.SortOrder.LayoutOrder
    listLayout.Parent        = list

    local selected = default
    local allBtns  = {}
    local _close   -- forward declare agar bisa dipakai dalam buildItems closure

    local function buildItems(filter)
        for _, b in ipairs(allBtns) do b:Destroy() end
        allBtns = {}
        local count = 0
        for _, item in ipairs(items) do
            if not filter or item:lower():find(filter:lower(), 1, true) then
                local row = Instance.new("TextButton")
                row.BackgroundTransparency = 1
                row.BorderSizePixel        = 0
                row.Size                   = UDim2.new(1, 0, 0, 30)
                row.Text                   = ""
                row.AutoButtonColor        = false
                row.ZIndex = 3
                row.Parent                 = list

                local pad = Instance.new("UIPadding")
                pad.PaddingLeft  = UDim.new(0, 10)
                pad.PaddingRight = UDim.new(0, 10)
                pad.Parent       = row

                local lbl = Instance.new("TextLabel")
                lbl.BackgroundTransparency = 1
                lbl.Size                   = UDim2.new(1, -16, 1, 0)
                lbl.Text                   = item
                lbl.Font                   = Enum.Font.Gotham
                lbl.TextSize               = 13
                lbl.TextColor3             = item == selected and Theme:Accent() or Theme:Text(2)
                lbl.TextXAlignment         = Enum.TextXAlignment.Left
                lbl.ZIndex = 3
                lbl.Parent                 = row

                if item == selected then
                    local check = Instance.new("TextLabel")
                    check.BackgroundTransparency = 1
                    check.Size                   = UDim2.fromOffset(12, 30)
                    check.Position               = UDim2.new(1, -12, 0, 0)
                    check.Text                   = "✓"
                    check.TextSize               = 13
                    check.Font                   = Enum.Font.GothamBold
                    check.TextColor3             = Theme:Accent()
                    check.ZIndex = 3
                    check.Parent                 = row
                end

                row.MouseEnter:Connect(function()
                    row.BackgroundTransparency = 0
                    Tween.fast(row, { BackgroundColor3 = Theme:BG(4) })
                end)
                row.MouseLeave:Connect(function()
                    Tween.fast(row, { BackgroundColor3 = Theme:BG(3) })
                    row.BackgroundTransparency = 1
                end)

                row.MouseButton1Click:Connect(function()
                    selected    = item
                    valLbl.Text = item
                    if flag then flag:_fire(item) end
                    if opts.Callback then pcall(opts.Callback, item) end
                    _close()
                end)

                table.insert(allBtns, row)
                count = count + 1
            end
        end

        local itemH    = 30
        local maxItems = math.min(count, 6)
        local menuH    = (maxItems * itemH) + (searchable and 33 or 0) + 8
        menu.Size      = UDim2.fromOffset(trigger.AbsoluteSize.X, menuH)
        list.Size      = UDim2.new(1, 0, 1, searchable and -33 or 0)
    end

    local open = false

    _close = function()
        open = false
        menu.Visible    = false
        menu.Parent     = card
        blocker.Visible = false
        blocker.Parent  = card
        Tween.fast(arrow, { Rotation = 0 })
        arrow.TextColor3 = Theme:Text(3)
        trigStroke.Color = Theme:Border(1)
        if searchBox then searchBox.Text = "" end
    end

    -- ScreenGui khusus dropdown dengan DisplayOrder lebih tinggi dari window (999)
    local _dropSG = nil
    local function getDropSG()
        -- Destroy stale instance agar property baru ter-apply
        if _dropSG then
            pcall(function() _dropSG:Destroy() end)
            _dropSG = nil
        end
        local CoreGui = game:GetService("CoreGui")
        -- Juga destroy any existing MuvaUI_Dropdown dari run sebelumnya
        for _, v in ipairs(CoreGui:GetChildren()) do
            if v.Name == "MuvaUI_Dropdown" then v:Destroy() end
        end
        local sg = Instance.new("ScreenGui")
        sg.Name           = "MuvaUI_Dropdown"
        sg.ResetOnSpawn   = false
        sg.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
        sg.DisplayOrder   = 9
        sg.IgnoreGuiInset = false
        pcall(function() sg.Parent = CoreGui end)
        _dropSG = sg
        return sg
    end

    local function openMenu()
        open = true

        local sg           = getDropSG()
        local absPosBefore = trigger.AbsolutePosition
        local absSize      = trigger.AbsoluteSize

        -- Blocker full-screen di belakang menu
        blocker.Parent  = sg
        blocker.Visible = true

        -- Reparent menu
        menu.Parent = sg

        local screenW = workspace.CurrentCamera.ViewportSize.X
        local screenH = workspace.CurrentCamera.ViewportSize.Y
        local menuW   = absSize.X

        -- Auto X: kalau menu keluar kanan layar, geser ke kiri
        local menuX = absPosBefore.X
        if menuX + menuW > screenW then
            menuX = screenW - menuW - 4
        end

        -- Auto Y: kalau menu keluar bawah layar, munculkan ke atas trigger
        local estMenuH = 200
        local menuY = absPosBefore.Y + absSize.Y + 4
        if menuY + estMenuH > screenH then
            menuY = absPosBefore.Y - estMenuH - 4
        end

        menu.Position = UDim2.fromOffset(menuX, menuY)
        menu.Size     = UDim2.fromOffset(menuW, 0)

        buildItems(nil)
        menu.Visible = true

        Tween.fast(arrow, { Rotation = 180 })
        arrow.TextColor3 = Theme:Accent()
        trigStroke.Color = Theme:Accent()
    end

    trigger.MouseButton1Click:Connect(function()
        if open then _close() else openMenu() end
    end)

    if searchBox then
        searchBox:GetPropertyChangedSignal("Text"):Connect(function()
            if not open then return end
            buildItems(searchBox.Text ~= "" and searchBox.Text or nil)
        end)
    end

    -- Outside click handled by blocker button

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    if flag then
        flag:OnChanged(function(v)
            selected    = v
            valLbl.Text = v
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/input/MultiDropdown.lua ─────────────────────
-- MultiDropdown: multi-select dengan tag chips
Section.AddMultiDropdown = function(self, opts)
    assert(type(opts) == "table", "AddMultiDropdown: opts must be a table")
    local items    = opts.Options or opts.Items or {}
    local defaults = opts.Default or {}
    local flag     = self:_registerFlag(opts.ID, defaults)

    local card, stroke = self:_makeCard()
    card.ClipsDescendants = false
    card.Size             = UDim2.new(1, 0, 0, 60)

    for _, c in ipairs(card:GetChildren()) do
        if c:IsA("UIPadding") then c:Destroy() end
    end

    local title = Instance.new("TextLabel")
    title.BackgroundTransparency = 1
    title.Size                   = UDim2.new(1, -24, 0, 14)
    title.Position               = UDim2.new(0, 12, 0, 10)
    title.Text                   = opts.Title or ""
    title.Font                   = Layout.FONT_TITLE
    title.TextSize               = Layout.TITLE_SIZE
    title.TextColor3             = Theme:Text(1)
    title.TextXAlignment         = Enum.TextXAlignment.Left
    title.Parent                 = card

    -- Trigger
    local trigger = Instance.new("TextButton")
    trigger.BackgroundColor3 = Theme:BG(1)
    trigger.BorderSizePixel  = 0
    trigger.Size             = UDim2.new(1, -24, 0, 28)
    trigger.Position         = UDim2.new(0, 12, 0, 28)
    trigger.AutomaticSize    = Enum.AutomaticSize.None
    trigger.Text             = ""
    trigger.AutoButtonColor  = false
    trigger.Parent           = card

    local trigCorner = Instance.new("UICorner")
    trigCorner.CornerRadius = UDim.new(0, 6)
    trigCorner.Parent       = trigger

    local trigStroke = Instance.new("UIStroke")
    trigStroke.Color     = Theme:Border(1)
    trigStroke.Thickness = 1
    trigStroke.Parent    = trigger

    local trigPad = Instance.new("UIPadding")
    trigPad.PaddingLeft   = UDim.new(0, 8)
    trigPad.PaddingRight  = UDim.new(0, 24)
    trigPad.PaddingTop    = UDim.new(0, 5)
    trigPad.PaddingBottom = UDim.new(0, 5)
    trigPad.Parent        = trigger

    -- Tags container
    local tagsFrame = Instance.new("Frame")
    tagsFrame.BackgroundTransparency = 1
    tagsFrame.Size                   = UDim2.new(1, 0, 0, 0)
    tagsFrame.AutomaticSize          = Enum.AutomaticSize.Y
    tagsFrame.Parent                 = trigger

    local tagsLayout = Instance.new("UIListLayout")
    tagsLayout.FillDirection        = Enum.FillDirection.Horizontal
    tagsLayout.VerticalAlignment    = Enum.VerticalAlignment.Center
    tagsLayout.Wraps                = true
    tagsLayout.Padding              = UDim.new(0, 3)
    tagsLayout.Parent               = tagsFrame

    local placeholder = Instance.new("TextLabel")
    placeholder.BackgroundTransparency = 1
    placeholder.Size                   = UDim2.new(1, 0, 0, 18)
    placeholder.Text                   = "Select options..."
    placeholder.Font                   = Enum.Font.Gotham
    placeholder.TextSize               = 13
    placeholder.TextColor3             = Theme:Text(4)
    placeholder.TextXAlignment         = Enum.TextXAlignment.Left
    placeholder.Name                   = "Placeholder"
    placeholder.Parent                 = tagsFrame

    local arrow = Instance.new("TextLabel")
    arrow.BackgroundTransparency = 1
    arrow.Size                   = UDim2.fromOffset(12, 18)
    arrow.Position               = UDim2.new(1, -4, 0, 5)
    arrow.Text                   = "▾"
    arrow.Font                   = Enum.Font.Gotham
    arrow.TextSize               = 12
    arrow.TextColor3             = Theme:Text(3)
    arrow.Parent                 = trigger

    -- ScreenGui khusus dropdown — destroy dan recreate setiap open
    local function getDropSG()
        local CoreGui = game:GetService("CoreGui")
        for _, v in ipairs(CoreGui:GetChildren()) do
            if v.Name == "MuvaUI_Dropdown" then pcall(function() v:Destroy() end) end
        end
        local sg = Instance.new("ScreenGui")
        sg.Name           = "MuvaUI_Dropdown"
        sg.ResetOnSpawn   = false
        sg.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
        sg.DisplayOrder   = 9
        sg.IgnoreGuiInset = false
        pcall(function() sg.Parent = CoreGui end)
        return sg
    end

    -- Menu di-parent ke ScreenGui saat open agar tidak ter-clip ScrollingFrame
    local menu = Instance.new("ScrollingFrame")
    menu.BackgroundColor3      = Theme:BG(3)
    menu.BorderSizePixel       = 0
    menu.Size                  = UDim2.fromOffset(200, 0)
    menu.Position              = UDim2.fromOffset(0, 0)
    menu.CanvasSize            = UDim2.new(0, 0, 0, 0)
    menu.AutomaticCanvasSize   = Enum.AutomaticSize.Y
    menu.ScrollBarThickness    = 2
    menu.ScrollBarImageColor3  = Theme:BG(4)
    menu.Visible               = false
    menu.ZIndex = 3
    menu.ClipsDescendants      = false
    menu.Parent                = card

    local menuCorner = Instance.new("UICorner")
    menuCorner.CornerRadius = UDim.new(0, 7)
    menuCorner.Parent       = menu

    local menuStroke = Instance.new("UIStroke")
    menuStroke.Color     = Theme:Border(2)
    menuStroke.Thickness = 1
    menuStroke.Parent    = menu

    local menuLayout = Instance.new("UIListLayout")
    menuLayout.FillDirection = Enum.FillDirection.Vertical
    menuLayout.SortOrder     = Enum.SortOrder.LayoutOrder
    menuLayout.Parent        = menu

    -- State
    local selected = {}
    for _, v in ipairs(defaults) do selected[v] = true end

    local tagObjects = {}

    local function refreshTags()
        -- Clear old tags
        for _, t in pairs(tagObjects) do t:Destroy() end
        tagObjects = {}

        local hasAny = false
        for item, active in pairs(selected) do
            if active then
                hasAny = true
                local tag = Instance.new("Frame")
                tag.BackgroundColor3 = Theme:BG(4)
                tag.BorderSizePixel  = 0
                tag.Size             = UDim2.fromOffset(0, 18)
                tag.AutomaticSize    = Enum.AutomaticSize.X
                tag.Parent           = tagsFrame

                local tagCorner = Instance.new("UICorner")
                tagCorner.CornerRadius = UDim.new(0, 4)
                tagCorner.Parent       = tag

                local tagPad = Instance.new("UIPadding")
                tagPad.PaddingLeft  = UDim.new(0, 5)
                tagPad.PaddingRight = UDim.new(0, 5)
                tagPad.Parent       = tag

                local tagRow = Instance.new("UIListLayout")
                tagRow.FillDirection     = Enum.FillDirection.Horizontal
                tagRow.VerticalAlignment = Enum.VerticalAlignment.Center
                tagRow.Padding           = UDim.new(0, 3)
                tagRow.Parent            = tag

                local tagLbl = Instance.new("TextLabel")
                tagLbl.BackgroundTransparency = 1
                tagLbl.Size                   = UDim2.fromOffset(0, 18)
                tagLbl.AutomaticSize          = Enum.AutomaticSize.X
                tagLbl.Text                   = item
                tagLbl.Font                   = Enum.Font.Gotham
                tagLbl.TextSize               = 12
                tagLbl.TextColor3             = Theme:Accent()
                tagLbl.Parent                 = tag

                local tagX = Instance.new("TextButton")
                tagX.BackgroundTransparency = 1
                tagX.BorderSizePixel        = 0
                tagX.Size                   = UDim2.fromOffset(10, 18)
                tagX.Text                   = "✕"
                tagX.Font                   = Enum.Font.GothamBold
                tagX.TextSize               = 8
                tagX.TextColor3             = Theme:Text(3)
                tagX.Parent                 = tag

                tagX.MouseButton1Click:Connect(function()
                    selected[item] = false
                    refreshTags()
                    local vals = {}
                    for k, v in pairs(selected) do if v then table.insert(vals, k) end end
                    if flag then flag:_fire(vals) end
                    if opts.Callback then pcall(opts.Callback, vals) end
                end)

                table.insert(tagObjects, tag)
            end
        end

        placeholder.Visible = not hasAny
    end

    local function buildMenu()
        for _, child in ipairs(menu:GetChildren()) do
            if child:IsA("TextButton") then child:Destroy() end
        end

        local count = 0
        for _, item in ipairs(items) do
            local row = Instance.new("TextButton")
            row.BackgroundTransparency = 1
            row.BorderSizePixel        = 0
            row.Size                   = UDim2.new(1, 0, 0, 30)
            row.Text                   = ""
            row.AutoButtonColor        = false
            row.ZIndex                 = 52
            row.Parent                 = menu

            local pad = Instance.new("UIPadding")
            pad.PaddingLeft  = UDim.new(0, 10)
            pad.PaddingRight = UDim.new(0, 10)
            pad.Parent       = row

            local check = Instance.new("Frame")
            check.Size             = UDim2.fromOffset(13, 13)
            check.Position         = UDim2.new(0, 0, 0.5, -6)
            check.BackgroundColor3 = selected[item] and Theme:Accent() or Theme:BG(1)
            check.BorderSizePixel  = 0
            check.ZIndex           = 53
            check.Parent           = row

            local checkCorner = Instance.new("UICorner")
            checkCorner.CornerRadius = UDim.new(0, 3)
            checkCorner.Parent       = check

            local checkStroke = Instance.new("UIStroke")
            checkStroke.Color     = selected[item] and Theme:Accent() or Theme:Border(1)
            checkStroke.Thickness = 1
            checkStroke.Parent    = check

            local checkMark = Instance.new("TextLabel")
            checkMark.BackgroundTransparency = 1
            checkMark.Size                   = UDim2.new(1, 0, 1, 0)
            checkMark.Text                   = selected[item] and "✓" or ""
            checkMark.Font                   = Enum.Font.GothamBold
            checkMark.TextSize               = 8
            checkMark.TextColor3             = Color3.new(1, 1, 1)
            checkMark.ZIndex                 = 54
            checkMark.Parent                 = check

            local lbl = Instance.new("TextLabel")
            lbl.BackgroundTransparency = 1
            lbl.Size                   = UDim2.new(1, -22, 1, 0)
            lbl.Position               = UDim2.new(0, 20, 0, 0)
            lbl.Text                   = item
            lbl.Font                   = Enum.Font.Gotham
            lbl.TextSize               = 13
            lbl.TextColor3             = selected[item] and Theme:Accent() or Theme:Text(2)
            lbl.TextXAlignment         = Enum.TextXAlignment.Left
            lbl.ZIndex                 = 53
            lbl.Parent                 = row

            row.MouseEnter:Connect(function()
                Tween.fast(row, { BackgroundColor3 = Theme:BG(4) })
                row.BackgroundTransparency = 0
            end)
            row.MouseLeave:Connect(function()
                row.BackgroundTransparency = 1
            end)

            row.MouseButton1Click:Connect(function()
                selected[item] = not selected[item]
                check.BackgroundColor3 = selected[item] and Theme:Accent() or Theme:BG(1)
                checkStroke.Color      = selected[item] and Theme:Accent() or Theme:Border(1)
                checkMark.Text         = selected[item] and "✓" or ""
                lbl.TextColor3         = selected[item] and Theme:Accent() or Theme:Text(2)
                refreshTags()
                local vals = {}
                for k, v in pairs(selected) do if v then table.insert(vals, k) end end
                if flag then flag:_fire(vals) end
                if opts.Callback then pcall(opts.Callback, vals) end
            end)

            count = count + 1
        end

        local menuH = math.min(count, 6) * 30 + 8
        menu.Size   = UDim2.fromOffset(trigger.AbsoluteSize.X, menuH)
    end

    local open = false

    -- Blocker full-screen: di-connect SEKALI di init, bukan di dalam openMenu
    local blocker = Instance.new("TextButton")
    blocker.BackgroundTransparency = 1
    blocker.BorderSizePixel        = 0
    blocker.Size                   = UDim2.new(1, 0, 1, 0)
    blocker.Text                   = ""
    blocker.AutoButtonColor        = false
    blocker.ZIndex = 3
    blocker.Visible                = false
    blocker.Parent                 = card

    local _close  -- forward declare

    _close = function()
        open             = false
        menu.Visible     = false
        menu.Parent      = card
        blocker.Visible  = false
        blocker.Parent   = card
        arrow.TextColor3 = Theme:Text(3)
        trigStroke.Color = Theme:Border(1)
        Tween.fast(arrow, { Rotation = 0 })
    end

    -- Blocker connected once at init
    blocker.MouseButton1Click:Connect(function() _close() end)

    trigger.MouseButton1Click:Connect(function()
        if open then
            _close()
        else
            open = true
            local sg      = getDropSG()
            local absPos  = trigger.AbsolutePosition  -- baca SEBELUM reparent
            local absSize = trigger.AbsoluteSize

            blocker.Parent  = sg
            blocker.Visible = true
            menu.Parent     = sg

            local screenW  = workspace.CurrentCamera.ViewportSize.X
            local screenH  = workspace.CurrentCamera.ViewportSize.Y
            local menuW    = absSize.X
            local estMenuH = math.min(#items, 6) * 30 + 8

            local menuX = absPos.X
            if menuX + menuW > screenW then menuX = screenW - menuW - 4 end
            local menuY = absPos.Y + absSize.Y + 4
            if menuY + estMenuH > screenH then menuY = absPos.Y - estMenuH - 4 end

            menu.Position    = UDim2.fromOffset(menuX, menuY)
            menu.Size        = UDim2.fromOffset(menuW, 0)
            buildMenu()
            menu.Visible     = true
            arrow.TextColor3 = Theme:Accent()
            trigStroke.Color = Theme:Accent()
            Tween.fast(arrow, { Rotation = 180 })
        end
    end)

    refreshTags()

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    table.insert(self._components, card)
    return card
end


-- ─── components/input/Keybind.lua ───────────────────────────
-- Keybind: klik lalu tekan key untuk rebind
local UserInputService = game:GetService("UserInputService")

-- Map KeyCode.Name → label pendek yang user-friendly
local KEY_LABELS = {
    -- Angka row atas
    Zero = "0", One = "1", Two = "2", Three = "3", Four = "4",
    Five = "5", Six = "6", Seven = "7", Eight = "8", Nine = "9",
    -- Numpad
    KeypadZero = "KP0", KeypadOne = "KP1", KeypadTwo = "KP2",
    KeypadThree = "KP3", KeypadFour = "KP4", KeypadFive = "KP5",
    KeypadSix = "KP6", KeypadSeven = "KP7", KeypadEight = "KP8",
    KeypadNine = "KP9",
    KeypadPlus = "KP+", KeypadMinus = "KP-", KeypadAsterisk = "KP*",
    KeypadSlash = "KP/", KeypadPeriod = "KP.", KeypadEnter = "KP↵",
    -- Modifier
    LeftShift = "L.SHIFT", RightShift = "R.SHIFT",
    LeftControl = "L.CTRL", RightControl = "R.CTRL",
    LeftAlt = "L.ALT", RightAlt = "R.ALT",
    LeftMeta = "L.WIN", RightMeta = "R.WIN",
    -- Navigasi
    Up = "↑", Down = "↓", Left = "←", Right = "→",
    Home = "HOME", End = "END",
    PageUp = "PGUP", PageDown = "PGDN",
    Insert = "INS", Delete = "DEL",
    -- Spesial
    Return = "ENTER", BackSpace = "BKSP", Tab = "TAB",
    Space = "SPACE", Escape = "ESC", CapsLock = "CAPS",
    -- Tanda baca umum
    Minus = "-", Equals = "=", LeftBracket = "[", RightBracket = "]",
    BackSlash = "\\", Semicolon = ";", Quote = "'",
    Comma = ",", Period = ".", Slash = "/",
    Backquote = "`",
}

Section.AddKeybind = function(self, opts)
    assert(type(opts) == "table", "AddKeybind: opts must be a table")
    local default = opts.Default or Enum.KeyCode.Unknown
    local flag    = self:_registerFlag(opts.ID, default)

    local card, stroke = self:_makeCard()

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Info
    local info = self:_makeInfoBlock(card, opts.Title, opts.Desc, 80)

    -- Key label button — style sama dengan value label di Slider
    local keyBtn = Instance.new("TextButton")
    keyBtn.BackgroundTransparency = 1
    keyBtn.BorderSizePixel        = 0
    keyBtn.Size                   = UDim2.fromOffset(68, 26)
    keyBtn.LayoutOrder            = 99
    keyBtn.AutoButtonColor        = false
    keyBtn.Font                   = Layout.FONT_BOLD
    keyBtn.TextSize               = Layout.TITLE_SIZE
    keyBtn.TextColor3             = Theme:Accent()
    keyBtn.TextXAlignment         = Enum.TextXAlignment.Right
    keyBtn.Parent                 = card

    -- Stroke tipis hanya saat listening
    local keyStroke = Instance.new("UIStroke")
    keyStroke.Color     = Theme:Accent()
    keyStroke.Thickness = 0
    keyStroke.Parent    = keyBtn

    local keyCorner = Instance.new("UICorner")
    keyCorner.CornerRadius = UDim.new(0, 5)
    keyCorner.Parent       = keyBtn

    local function keyName(kc)
        if kc == Enum.KeyCode.Unknown then return "NONE" end
        return KEY_LABELS[kc.Name] or kc.Name:upper()
    end

    local value    = default
    local listening = false

    keyBtn.Text = keyName(value)

    local function setListening(state)
        listening = state
        if state then
            keyBtn.Text          = "..."
            keyBtn.TextColor3    = Theme:Text(3)
            keyStroke.Thickness  = 1
            keyStroke.Color      = Theme:Accent()
        else
            keyBtn.Text          = keyName(value)
            keyBtn.TextColor3    = Theme:Accent()
            keyStroke.Thickness  = 0
        end
    end

    keyBtn.MouseButton1Click:Connect(function()
        setListening(not listening)
    end)

    UserInputService.InputBegan:Connect(function(input, gpe)
        if not listening then return end
        if input.UserInputType == Enum.UserInputType.Keyboard then
            if input.KeyCode == Enum.KeyCode.Escape then
                setListening(false)
                return
            end
            value = input.KeyCode
            setListening(false)
            if flag then flag:_fire(value) end
            if opts.Callback then pcall(opts.Callback, value) end
        end
    end)

    keyBtn.MouseEnter:Connect(function()
        if not listening then
            Tween.fast(keyBtn, { TextColor3 = Color.lighten(Theme:Accent(), 0.15) })
        end
    end)
    keyBtn.MouseLeave:Connect(function()
        if not listening then
            Tween.fast(keyBtn, { TextColor3 = Theme:Accent() })
        end
    end)

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    Theme:OnAccentChanged(function(accent)
        keyBtn.TextColor3 = accent
    end)

    if flag then
        flag:OnChanged(function(v)
            value     = v
            keyBtn.Text = keyName(v)
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/input/ColorPicker.lua ───────────────────────
-- ColorPicker: preset swatch palette (tanpa slider/hue bar)
local PRESETS = {
    "#A855F7","#8B5CF6","#6366F1","#3B82F6","#06B6D4","#22C55E",
    "#EAB308","#F97316","#EF4444","#EC4899","#F43F5E","#14B8A6",
    "#FFFFFF","#D4D4D8","#A1A1AA","#71717A","#52525B","#27272A",
    "#FDE68A","#BBF7D0","#BAE6FD","#E9D5FF","#FECACA","#FED7AA",
}

Section.AddColorPicker = function(self, opts)
    assert(type(opts) == "table", "AddColorPicker: opts must be a table")
    local default = opts.Default or Color.fromHex("#A855F7")
    local flag    = self:_registerFlag(opts.ID, default)

    local card, stroke = self:_makeCard()
    card.ClipsDescendants = false

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Info
    local info = self:_makeInfoBlock(card, opts.Title, opts.Desc, 46)

    -- Color preview button
    local previewBtn = Instance.new("TextButton")
    previewBtn.BackgroundColor3 = default
    previewBtn.BorderSizePixel  = 0
    previewBtn.Size             = UDim2.fromOffset(30, 30)
    previewBtn.LayoutOrder      = 99
    previewBtn.Text             = ""
    previewBtn.AutoButtonColor  = false
    previewBtn.Parent           = card

    local pvCorner = Instance.new("UICorner")
    pvCorner.CornerRadius = UDim.new(0, 7)
    pvCorner.Parent       = previewBtn

    local pvStroke = Instance.new("UIStroke")
    pvStroke.Color     = Theme:Border(1)
    pvStroke.Thickness = 2
    pvStroke.Parent    = previewBtn

    -- Palette popup — hanya preset grid
    local palette = Instance.new("Frame")
    palette.BackgroundColor3 = Theme:BG(3)
    palette.BorderSizePixel  = 0
    palette.Size             = UDim2.fromOffset(188, 0)
    palette.AutomaticSize    = Enum.AutomaticSize.Y
    palette.Visible          = false
    palette.ZIndex = 3
    palette.Parent           = card

    local palCorner = Instance.new("UICorner")
    palCorner.CornerRadius = UDim.new(0, 10)
    palCorner.Parent       = palette

    local palStroke = Instance.new("UIStroke")
    palStroke.Color     = Theme:Border(2)
    palStroke.Thickness = 1
    palStroke.Parent    = palette

    local palPad = Instance.new("UIPadding")
    palPad.PaddingLeft   = UDim.new(0, 10)
    palPad.PaddingRight  = UDim.new(0, 10)
    palPad.PaddingTop    = UDim.new(0, 10)
    palPad.PaddingBottom = UDim.new(0, 10)
    palPad.Parent        = palette

    -- Grid swatches
    local grid = Instance.new("Frame")
    grid.BackgroundTransparency = 1
    grid.Size                   = UDim2.new(1, 0, 0, 0)
    grid.AutomaticSize          = Enum.AutomaticSize.Y
    grid.Parent                 = palette

    local gridLayout = Instance.new("UIGridLayout")
    gridLayout.CellSize    = UDim2.fromOffset(26, 26)
    gridLayout.CellPadding = UDim2.fromOffset(5, 5)
    gridLayout.Parent      = grid

    local value = default
    local selectedStroke = nil  -- track swatch terpilih

    local function selectColor(c, hex, swStroke)
        value = c
        previewBtn.BackgroundColor3 = c
        -- reset stroke swatch sebelumnya
        if selectedStroke then
            selectedStroke.Thickness = 0
        end
        selectedStroke = swStroke
        if selectedStroke then
            selectedStroke.Color     = Color3.new(1, 1, 1)
            selectedStroke.Thickness = 2
        end
        if flag then flag:_fire(c) end
        if opts.Callback then pcall(opts.Callback, c) end
    end

    for _, hex in ipairs(PRESETS) do
        local sw = Instance.new("TextButton")
        sw.BackgroundColor3 = Color.fromHex(hex)
        sw.BorderSizePixel  = 0
        sw.Size             = UDim2.fromOffset(26, 26)
        sw.Text             = ""
        sw.AutoButtonColor  = false
        sw.ZIndex           = 62
        sw.Parent           = grid

        local swCorner = Instance.new("UICorner")
        swCorner.CornerRadius = UDim.new(0, 5)
        swCorner.Parent       = sw

        local swStroke = Instance.new("UIStroke")
        swStroke.Thickness = 0
        swStroke.Parent    = sw

        -- Mark default sebagai terpilih
        if Color.toHex(default):lower() == hex:lower() then
            selectedStroke           = swStroke
            swStroke.Color           = Color3.new(1, 1, 1)
            swStroke.Thickness       = 2
        end

        sw.MouseButton1Click:Connect(function()
            selectColor(Color.fromHex(hex), hex, swStroke)
        end)

        sw.MouseEnter:Connect(function()
            Tween.fast(sw, { Size = UDim2.fromOffset(28, 28) })
        end)
        sw.MouseLeave:Connect(function()
            Tween.fast(sw, { Size = UDim2.fromOffset(26, 26) })
        end)
    end

    -- Open / close palette
    local open   = false
    local _palSG = nil

    local function closePalette()
        open = false
        palette.Visible = false
        palette.Parent  = card
        if _palSG then
            pcall(function() _palSG:Destroy() end)
            _palSG = nil
        end
        pvStroke.Color = Theme:Border(1)
    end

    local function openPalette()
        open = true
        pvStroke.Color = Theme:Accent()

        local absPos  = previewBtn.AbsolutePosition
        local absSize = previewBtn.AbsoluteSize

        local CoreGui = game:GetService("CoreGui")
        for _, v in ipairs(CoreGui:GetChildren()) do
            if v.Name == "MuvaUI_ColorPicker" then
                pcall(function() v:Destroy() end)
            end
        end
        local sg = Instance.new("ScreenGui")
        sg.Name           = "MuvaUI_ColorPicker"
        sg.ResetOnSpawn   = false
        sg.ZIndexBehavior = Enum.ZIndexBehavior.Sibling
        sg.DisplayOrder   = 9
        sg.IgnoreGuiInset = false
        pcall(function() sg.Parent = CoreGui end)
        _palSG = sg

        local blocker = Instance.new("TextButton")
        blocker.BackgroundTransparency = 1
        blocker.BorderSizePixel        = 0
        blocker.Size                   = UDim2.new(1, 0, 1, 0)
        blocker.Text                   = ""
        blocker.AutoButtonColor        = false
        blocker.ZIndex = 3
        blocker.Parent                 = sg
        blocker.MouseButton1Click:Connect(function() closePalette() end)

        palette.Parent = sg

        local palW    = 188
        local screenW = workspace.CurrentCamera.ViewportSize.X
        local posX    = absPos.X - palW - 6
        if posX < 0 then posX = absPos.X + absSize.X + 6 end
        if posX + palW > screenW then posX = absPos.X end

        palette.Position = UDim2.fromOffset(posX, absPos.Y)
        palette.Visible  = true
    end

    -- Auto-close saat tab berganti
    local function isCardVisible()
        local p = card.Parent
        while p do
            local ok, visible = pcall(function() return p.Visible end)
            if ok and visible == false then return false end
            p = p.Parent
        end
        return true
    end

    game:GetService("RunService").Heartbeat:Connect(function()
        if open and not isCardVisible() then closePalette() end
    end)

    previewBtn.MouseButton1Click:Connect(function()
        if open then closePalette() else openPalette() end
    end)

    previewBtn.MouseEnter:Connect(function()
        Tween.fast(previewBtn, { Size = UDim2.fromOffset(32, 32) })
        pvStroke.Color = Theme:Accent()
    end)
    previewBtn.MouseLeave:Connect(function()
        Tween.fast(previewBtn, { Size = UDim2.fromOffset(30, 30) })
        if not open then pvStroke.Color = Theme:Border(1) end
    end)

    card.MouseEnter:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(3) })
        stroke.Color = Theme:Border(1)
    end)
    card.MouseLeave:Connect(function()
        Tween.fast(card, { BackgroundColor3 = Theme:BG(2) })
        stroke.Color = Theme:Border(0)
    end)

    if flag then
        flag:OnChanged(function(v)
            value = v
            previewBtn.BackgroundColor3 = v
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/display/Button.lua ──────────────────────────
-- Button: aksi tombol dengan 5 style variant
local STYLES = {
    Default = {
        bg     = function() return Theme:BG(4) end,
        bgHov  = function() return Theme:Accent() end,
        text   = function() return Theme:Accent() end,
        textHov= function() return Color3.new(1,1,1) end,
        border = function() return Theme:Border(1) end,
        borderHov = function() return Theme:Accent() end,
    },
    Danger = {
        bg     = function() return Color.fromHex("#1a0a0a") end,
        bgHov  = function() return Color.fromHex("#ef4444") end,
        text   = function() return Color.fromHex("#f87171") end,
        textHov= function() return Color3.new(1,1,1) end,
        border = function() return Color.fromHex("#3b1010") end,
        borderHov = function() return Color.fromHex("#ef4444") end,
    },
    Success = {
        bg     = function() return Color.fromHex("#0a1a0e") end,
        bgHov  = function() return Color.fromHex("#22c55e") end,
        text   = function() return Color.fromHex("#4ade80") end,
        textHov= function() return Color3.new(1,1,1) end,
        border = function() return Color.fromHex("#0e2e18") end,
        borderHov = function() return Color.fromHex("#22c55e") end,
    },
    Ghost = {
        bg     = function() return Color3.new(0,0,0) end,
        bgHov  = function() return Theme:BG(3) end,
        text   = function() return Theme:Text(3) end,
        textHov= function() return Theme:Text(0) end,
        border = function() return Theme:Border(1) end,
        borderHov = function() return Theme:Border(2) end,
    },
    Warn = {
        bg     = function() return Color.fromHex("#1a1500") end,
        bgHov  = function() return Color.fromHex("#eab308") end,
        text   = function() return Color.fromHex("#fbbf24") end,
        textHov= function() return Color3.new(0,0,0) end,
        border = function() return Color.fromHex("#2e2600") end,
        borderHov = function() return Color.fromHex("#eab308") end,
    },
}

Section.AddButton = function(self, opts)
    assert(type(opts) == "table", "AddButton: opts must be a table")
    local style = STYLES[opts.Style] or STYLES.Default

    local card, _ = self:_makeCard()

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Info (optional desc)
    if opts.Desc then
        local info = self:_makeInfoBlock(card, opts.Title, opts.Desc, 90)
        info.LayoutOrder = 1
    end

    -- Button
    local btn = Instance.new("TextButton")
    btn.BackgroundColor3 = style.bg()
    btn.BorderSizePixel  = 0
    btn.Size             = opts.Width and UDim2.fromOffset(opts.Width, 32)
                          or opts.Desc and UDim2.fromOffset(80, 26)
                          or UDim2.new(1, 0, 1, 0)
    btn.Text             = opts.Title or "Button"
    btn.Font             = Enum.Font.GothamBold
    btn.TextSize         = 11
    btn.TextColor3       = style.text()
    btn.AutoButtonColor  = false
    btn.LayoutOrder      = 99
    btn.Parent           = card

    local btnCorner = Instance.new("UICorner")
    btnCorner.CornerRadius = UDim.new(0, 6)
    btnCorner.Parent       = btn

    local btnStroke = Instance.new("UIStroke")
    btnStroke.Color     = style.border()
    btnStroke.Thickness = 1
    btnStroke.Parent    = btn

    btn.MouseEnter:Connect(function()
        Tween.fast(btn, { BackgroundColor3 = style.bgHov() })
        btn.TextColor3 = style.textHov()
        btnStroke.Color = style.borderHov()
    end)
    btn.MouseLeave:Connect(function()
        Tween.fast(btn, { BackgroundColor3 = style.bg() })
        btn.TextColor3 = style.text()
        btnStroke.Color = style.border()
    end)
    btn.MouseButton1Down:Connect(function()
        Tween.fast(btn, { Size = opts.Desc
            and UDim2.fromOffset(78, 24)
            or  UDim2.new(1, -2, 1, -2)
        })
    end)
    btn.MouseButton1Up:Connect(function()
        Tween.fast(btn, { Size = opts.Desc
            and UDim2.fromOffset(80, 26)
            or  UDim2.new(1, 0, 1, 0)
        })
    end)
    btn.MouseButton1Click:Connect(function()
        if opts.Callback then pcall(opts.Callback) end
    end)

    -- Accent update for Default style only
    if not opts.Style or opts.Style == "Default" then
        Theme:OnAccentChanged(function(accent)
            btn.TextColor3  = accent
            btnStroke.Color = Theme:Border(1)
        end)
    end

    table.insert(self._components, card)
    return card
end


-- ─── components/display/Badge.lua ───────────────────────────
-- Badge: status label inline
local BADGE_COLORS = {
    Purple = { bg = Color.fromHex("#1a0a2e"), text = Color.fromHex("#A855F7"), border = Color.fromHex("#2e1050") },
    Green  = { bg = Color.fromHex("#0a1a0e"), text = Color.fromHex("#22c55e"), border = Color.fromHex("#0e2e18") },
    Red    = { bg = Color.fromHex("#1a0a0a"), text = Color.fromHex("#ef4444"), border = Color.fromHex("#3b1010") },
    Yellow = { bg = Color.fromHex("#1a1500"), text = Color.fromHex("#eab308"), border = Color.fromHex("#2e2600") },
    Blue   = { bg = Color.fromHex("#0a1220"), text = Color.fromHex("#60a5fa"), border = Color.fromHex("#0e1e38") },
}

Section.AddBadge = function(self, opts)
    assert(type(opts) == "table", "AddBadge: opts must be a table")
    local colors = BADGE_COLORS[opts.Color] or BADGE_COLORS.Purple

    local card, stroke = self:_makeCard()

    local row = Instance.new("UIListLayout")
    row.FillDirection     = Enum.FillDirection.Horizontal
    row.VerticalAlignment = Enum.VerticalAlignment.Center
    row.Padding           = UDim.new(0, 8)
    row.Parent            = card

    -- Title
    local titleLbl = Instance.new("TextLabel")
